import { describe, it } from "vitest";

describe("MHPCO Claim Office - quote (premium calculation)", () => {
  it.todo(
    "empty item list, customer 0 years, 1st quote → premium 5 G (only the processing fee)",
  );

  it.todo(
    "single sword (steel, enchantment 0, not cursed), customer 0 years, 1st quote → premium 115 G (100 base + 10 first-insurance + 5 fee)",
  );

  it.todo(
    "single amulet (silver, enchantment 0, not cursed), customer 0 years, 1st quote → premium 71 G (60 base + 6 first-insurance + 5 fee)",
  );

  it.todo(
    "single staff (wood, enchantment 0, not cursed), customer 0 years, 1st quote → premium 93 G (80 base + 8 first-insurance + 5 fee)",
  );

  it.todo(
    "single potion, customer 0 years, 1st quote → premium 49 G (40 base + 4 first-insurance + 5 fee)",
  );

  it.todo(
    "single rune, customer 0 years, 1st quote → premium 33 G (25 base + 2.5 first-insurance + 5 fee = 32.5 rounded up to 33)",
  );

  it.todo(
    "2 runes (no block), customer 0 years, 1st quote → premium 60 G (50 base + 5 first-insurance + 5 fee)",
  );

  it.todo(
    "3 runes (block of 3), customer 0 years, 1st quote → premium 71 G (60 base + 6 first-insurance + 5 fee)",
  );

  it.todo(
    "4 runes (no block, block requires exactly 3), customer 0 years, 1st quote → premium 115 G (100 base + 10 first-insurance + 5 fee)",
  );

  it.todo(
    "7 runes (no block), customer 0 years, 1st quote → premium 198 G (175 base + 17.5 first-insurance + 5 fee = 197.5 rounded up to 198)",
  );

  it.todo(
    "2 runes + 1 moonstone (no block, alike requires same type), customer 0 years, 1st quote → premium 88 G (75 base + 7.5 first-insurance + 5 fee = 87.5 rounded up)",
  );

  it.todo(
    "3 runes + 3 moonstones (two separate blocks of 3 alike), customer 0 years, 1st quote → premium 137 G (120 base + 12 first-insurance + 5 fee)",
  );

  it.todo(
    "sword with enchantment 4, not cursed, customer 0 years, 1st quote → premium 115 G (no high-enchantment surcharge below threshold)",
  );

  it.todo(
    "sword with enchantment exactly 5, not cursed, customer 0 years, 1st quote → premium 145 G (100 base + 30 high-enchantment + 10 first-insurance + 5 fee)",
  );

  it.todo(
    "cursed sword with enchantment exactly 5, customer 0 years, 1st quote → premium 195 G (100 base + 50 curse + 30 high-enchantment + 10 first-insurance + 5 fee)",
  );

  it.todo(
    "plain sword, customer with exactly 2 years (loyalty applies), 1st quote → premium 95 G (100 base + 10 first-insurance − 20 loyalty + 5 fee)",
  );

  it.todo(
    "policy with a cursed sword and a plain amulet, customer 0 years, 1st quote → premium 231 G (item totals 100+60+50 curse = 210, + 16 first-insurance (10% of policy base 160) + 5 fee)",
  );

  it.todo(
    "integration: newcomer (0 years, 1st contract) with a cursed sword (steel, enchantment 3) → premium 165 G (100 base + 50 curse + 10 first-insurance + 5 fee)",
  );

  it.todo(
    "integration: long-standing customer (3 years, 2nd quote in scenario) with a cursed sword (steel, enchantment 7) → premium 160 G (100 base + 50 curse + 30 high-enchantment − 20 loyalty + 10 first-insurance − 15 follow-up + 5 fee)",
  );
});

describe("MHPCO Claim Office - claim (payout calculation)", () => {
  it.todo(
    "policy with one sword (cap 2000); steel sword enchantment 3, damage 500 → payout 400 G (full reimbursement minus 100 deductible), remainingCap 1600",
  );

  it.todo(
    "policy with one rune (insurance value 250, cap 500); damage 200 → payout 100 G (full reimbursement minus 100 deductible), remainingCap 400",
  );

  it.todo(
    "policy with dragon-material sword (enchantment 5); damage 800 → payout 700 G (only dragon clause: full reimbursement, then deductible), remainingCap 1300",
  );

  it.todo(
    "policy with steel sword enchantment 9; damage 1000 → payout 400 G (only high-enchantment clause: 50% then deductible: 500-100), remainingCap 1600",
  );

  it.todo(
    "policy with dragon-material sword enchantment 9; damage 1000 → payout 400 G (both clauses, 50% rule wins, then deductible), remainingCap 1600",
  );

  it.todo(
    "policy with dragon-material sword enchantment exactly 8; damage 1000 → payout 400 G (high-enchantment clause applies at threshold, then deductible: 500-100), remainingCap 1600",
  );

  it.todo(
    "policy with sword + amulet (cap 3200); damages [sword 500, amulet 300] → payout 600 G (deductible applies once per damaged item: 400+200), remainingCap 2600",
  );

  it.todo(
    "policy with two swords (insurance sum 2000, cap 4000); damages [sword 500, sword 300] → payout 600 G (each entry treated as a separate damage), remainingCap 3400",
  );

  it.todo(
    "cap exhaustion across two claims: sword (cap 2000); claim 1 damage 1500 → payout 1400, remainingCap 600; claim 2 damage 1500 → payout 600 (reduced to remaining cap), remainingCap 0",
  );

  it.todo(
    "rounding payouts down: dragon sword enchantment 9, damage 901 → payout 350 G (50% of 901 = 450.5, minus 100 deductible = 350.5, rounded down to 350)",
  );

  it.todo(
    "cap based on unmodified insurance value: cursed sword (insurance value 1000, premium modifiers do not raise cap) → cap is 2000 (verified via remainingCap after small claim)",
  );

  it.todo(
    "block discount does not lower insurance sum: policy with sword + 3 runes → insurance sum 1750 G, cap 3500 (verified via remainingCap)",
  );
});

describe("MHPCO Claim Office - CLI (stdin/stdout JSON)", () => {
  it.todo(
    "CLI reads scenario JSON from stdin and writes { results: [...] } to stdout in the same order as steps",
  );

  it.todo(
    "CLI quote result has shape { premium: <integer> } (schema example: customer 5 yrs, single amulet quote)",
  );

  it.todo(
    "CLI claim result has shape { payout: <integer>, remainingCap: <integer> } (schema example: amulet claim after the quote)",
  );

  it.todo(
    "CLI multi-step scenario (quote then claim) returns results array of length 2 with correct shapes",
  );

  it.todo(
    "CLI exits with non-zero status code when a quote contains an unknown item type (e.g. broomstick); writes error to stderr; does not write results to stdout",
  );

  it.todo(
    "CLI exits with non-zero status code when a claim references a damage entry whose item type is not part of the policy; writes error to stderr",
  );

  it.todo(
    "CLI exits with non-zero status code when a claim contains a damage entry with negative amount; writes error to stderr",
  );

  it.todo(
    "CLI exits with non-zero status code when a damages array contains more entries of a type than insured (e.g. two sword damages but only one sword insured); whole claim rejected",
  );
});
